module counter13bit_async_load (
    input clk,
    input load,
    input en,
    input [12:0] d,
    output [12:0] q
);

    reg [12:0] count_reg;

    always @(posedge clk or posedge load) begin
        if (load)
            count_reg <= d;
        else if (en)
            count_reg <= count_reg + 1;
    end

    assign q = count_reg;

endmodule
